const items = params.categoryId ? _.filter(samples.northwind.products, { categoryID: parseInt(params.categoryId, 10) }) : samples.northwind.products;
const page = parseInt(params.page ?? '1', 10);
const size = parseInt(params.size ?? '20', 10);
const start = (page - 1) * size;
return { total: items.length, page, size, items: items.slice(start, start + size) };

